import type { FC } from 'react';
import { cn } from '@/lib/utils';
import { type IconProps, type SvgProps, sizeMap } from '../types';

export type ModelClassProps = IconProps;

const ModelClassLight: FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title ? <title>{title}</title> : null}
    <path d="M15 8a7 7 0 1 0-7 7v-5a2 2 0 0 1 2-2z" fill="#EDF3FF" />
    <path d="M15 8a7 7 0 1 0-7 7v-1a6 6 0 1 1 6-6z" fill="#3574F0" />
    <path
      d="M8 10.573v.925C6.148 11.43 4.788 9.96 4.788 8c0-2.006 1.426-3.5 3.345-3.5 1.489 0 2.765.9 3.08 2.175h-1.016c-.314-.73-1.092-1.252-2.064-1.252-1.34 0-2.306 1.074-2.306 2.577 0 1.453.903 2.505 2.173 2.573"
      fill="#3574F0"
    />
    <path
      fillRule="evenodd"
      clipRule="evenodd"
      d="M10 9a1 1 0 0 0-1 1v5a1 1 0 0 0 1 1h5a1 1 0 0 0 1-1v-5a1 1 0 0 0-1-1zm0 2v-1h2v1zm0 1v3h2v-3zm3 3h2v-3h-2zm2-4v-1h-2v1z"
      fill="#6C707E"
    />
  </svg>
);

const ModelClassDark: FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title ? <title>{title}</title> : null}
    <path d="M15 8a7 7 0 1 0-7 7v-5a2 2 0 0 1 2-2z" fill="#25324D" />
    <path d="M15 8a7 7 0 1 0-7 7v-1a6 6 0 1 1 6-6z" fill="#548AF7" />
    <path
      d="M8 10.573v.925C6.148 11.43 4.788 9.96 4.788 8c0-2.006 1.426-3.5 3.345-3.5 1.489 0 2.765.9 3.08 2.175h-1.016c-.314-.73-1.092-1.252-2.064-1.252-1.34 0-2.306 1.074-2.306 2.577 0 1.453.903 2.505 2.173 2.573"
      fill="#548AF7"
    />
    <path
      fillRule="evenodd"
      clipRule="evenodd"
      d="M10 9a1 1 0 0 0-1 1v5a1 1 0 0 0 1 1h5a1 1 0 0 0 1-1v-5a1 1 0 0 0-1-1zm0 2v-1h2v1zm0 1v3h2v-3zm3 3h2v-3h-2zm2-4v-1h-2v1z"
      fill="#CED0D6"
    />
  </svg>
);

export const ModelClass: FC<ModelClassProps> = ({
  size = 'md',
  mode = 'light',
  className,
  'aria-label': ariaLabel,
  title,
  ...props
}) => {
  const SvgComponent = mode === 'light' ? ModelClassLight : ModelClassDark;

  return (
    <SvgComponent
      size={sizeMap[size]}
      className={cn('inline-block flex-shrink-0', className)}
      title={title}
      role={ariaLabel ? 'img' : 'presentation'}
      aria-label={ariaLabel}
      aria-hidden={!ariaLabel}
      {...props}
    />
  );
};
